refsection.programlisting:
url = "https://imagej.net/ij/images/mri-stack.zip";
zipFile = fullfile(TMPDIR, "ipcv_mri-stack.zip");
outDir = fullfile(TMPDIR, "ipcv_mri-stack");
stackFile = fullfile(outDir, "mri-stack.tif");

if ~isfile(zipFile) then
    http_get(url, zipFile, follow=%t, timeout=120);
end

if ~isfile(stackFile) then
    if ~isdir(outDir) then
        mkdir(outDir);
    end
    decompress(zipFile, outDir);
end

stack = imreadmulti(stackFile);
volume = squeeze(stack(:, :, 1, :));

view = imshow3d(volume);
